        // dist[i][j] = minimum path cost (or simply reachability) to reach node i using exactly j heavy edges.
        // Since we only care about reachability within k, a BFS on the state (node, heavy_count) is appropriate.

        // dist[i][j] stores true if node i is reachable using exactly j heavy edges.
        // Initialize all to false.
        const dist = Array(n).fill(0).map(() => Array(k + 1).fill(false));

        // Queue stores [node, heavy_count]
        const queue = [];

        // Start state
        dist[source][0] = true;
        queue.push([source, 0]);

        let head = 0;
        while (head < queue.length) {
            const [u, heavyCount] = queue[head++];

            if (u === target) {
                // Found a path, and since we are exploring layer by layer in terms of heavy_count,
                // this guarantees we found *a* path satisfying the condition.
                return true;
            }

            if (heavyCount <= k) {
                for (const [v, edgeIsHeavy] of adj[u]) {
                    const newHeavyCount = heavyCount + edgeIsHeavy;

                    if (newHeavyCount <= k && !dist[v][newHeavyCount]) {
                        dist[v][newHeavyCount] = true;
                        queue.push([v, newHeavyCount]);
                    }
                }
            }
        }

        // Check if target is reachable with any heavy count <= k
        for (let j = 0; j <= k; j++) {
            if (dist[target][j]) {
                return true;
            }
        }

        return false;
    }

    // Binary search over the sorted unique weights (potential thresholds)
    // We are looking for the *minimum* threshold such that check(threshold) is true.
    let low = 0;
    let high = sortedWeights.length - 1;
    let minThreshold = -1;

    while (low <= high) {
        const midIndex = Math.floor((low + high) / 2);
        const currentThreshold = sortedWeights[midIndex];

        if (check(currentThreshold)) {
            // This threshold works, try for a smaller one
            minThreshold = currentThreshold;
            high = midIndex - 1;
        } else {
            // This threshold is too small (or the graph is disconnected even with high threshold)
            // Need a larger threshold (which makes edges heavier, potentially allowing more paths, 
            // but the problem is about reducing heavy edges relative to the threshold).
            // Wait: A LARGER threshold means MORE edges become heavy (w > threshold). 
            // If check(T) fails, we need to decrease the number of heavy edges. 
            // To decrease heavy edges, we must INCREASE the threshold.
            low = midIndex + 1;
        }
    }

    return minThreshold;
}
